package be.schaubroeck.lpb.rkm.rekenmotor.rsz.werkbonus;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.Rszppo;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplCodeVermin;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplNotieGepens;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import com.google.common.collect.ImmutableSet;
import lombok.AllArgsConstructor;
import org.joda.time.LocalDate;

import java.util.Set;

@AllArgsConstructor
public class WerkbonusGepensioneerdOpper {

    private static final Set<String> NACE_CODES_ZORGSECTOR =
            ImmutableSet.of("86101", "86102", "86103", "86104", "86109", "86210", "86901", "86903", "86904", "86905", "86906", "86909", "87101", "87109", "87201",
                    "87202", "87203", "87204", "87205", "87209", "87301", "87302", "87303", "87304", "87309", "87901", "87902", "87909", "88101", "88102", "88103",
                    "88104", "88109", "88911", "88912", "88919", "88991", "88992", "88993", "88994", "88996", "88999");


    private static final Set<String> NACE_CODES_ZORGSECTOR_2025 =
            ImmutableSet.of("86101", "86102", "86103", "86104", "86109", "86210", "86910", "86920", "86931", "86932", "86933", "86939", "86940", "86951", "86952",
                    "86959", "86991", "86993", "86994", "86995", "86996", "86999", "87101", "87109", "87201", "87202", "87203", "87204", "87205", "87209", "87301",
                    "87302", "87303", "87304", "87309", "87991", "87992", "87999", "88101", "88102", "88103", "88104", "88105", "88106", "88109", "88911", "88912",
                    "88919", "88991", "88992", "88994", "88999");


    private ConstantManager constantManager;

    public boolean komtInAanMerking(Opper opper, RekenTijd rekenTijd) {
        Rszppo rszppo = opper.getRszppo();
        boolean isZorgSector = isZorgSector(rszppo.getNaceCode().trim(), rekenTijd);
        boolean isNotieGepensioeneerd = rszppo.getNotieGepensioneerd() == DmfapplNotieGepens.GEPENSION;
        return isZorgSector && isNotieGepensioeneerd;
    }

    public void checkWerkbonusHerstructurering(Opper opper, RegulManager regulManager) {
        DmfapplCodeVermin verminderingscode = opper.getRszppo().getCodeWerkbonus();
        if (verminderingscode == DmfapplCodeVermin.DMFAPPL_CODE_VERMIN_0601 || verminderingscode == DmfapplCodeVermin.DMFAPPL_CODE_VERMIN_0600) {
            regulManager.doRegulException(opper.getOpdracht(), Regulkode.COMBINATIE_WERKBONUS_HERSTRUCTERING_EN_GEPENSIONEERD);
        }
    }

    public boolean isZorgSector(String naceCode, RekenTijd rekenTijd) {
        LocalDate startDatumNace2025 = constantManager.getByCodeDatum(Konstanten.KST_STARTDATUM_NACE_2025, rekenTijd.eindDatum).getDatum();
        if (rekenTijd.beginDatum.isBefore(startDatumNace2025)) {
            return NACE_CODES_ZORGSECTOR.contains(naceCode);
        } else {
            return NACE_CODES_ZORGSECTOR_2025.contains(naceCode);
        }
    }
}
